#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="E:\Programe\Git\xxx252525.github.io\node_modules\stylus\bin\node_modules;E:\Programe\Git\xxx252525.github.io\node_modules\stylus\node_modules;E:\Programe\Git\xxx252525.github.io\node_modules;E:\Programe\Git\node_modules;E:\Programe\node_modules;E:\node_modules;E:\Programe\Git\xxx252525.github.io\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/e/Programe/Git/xxx252525.github.io/node_modules/stylus/bin/node_modules:/mnt/e/Programe/Git/xxx252525.github.io/node_modules/stylus/node_modules:/mnt/e/Programe/Git/xxx252525.github.io/node_modules:/mnt/e/Programe/Git/node_modules:/mnt/e/Programe/node_modules:/mnt/e/node_modules:/mnt/e/Programe/Git/xxx252525.github.io/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../stylus/bin/stylus" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../stylus/bin/stylus" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../stylus/bin/stylus" $args
  } else {
    & "node$exe"  "$basedir/../stylus/bin/stylus" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
